307:    logic[PAGE_NUM_BITS - 1:0] ppage_idx;
308:    logic[32 - (PAGE_NUM_BITS + 5) - 1:0] unused;
316:typedef logic[$clog2(`L1D_WAYS) - 1:0] l1d_way_idx_t;
317:typedef logic[$clog2(`L1D_SETS) - 1:0] l1d_set_idx_t;
318:typedef logic[DCACHE_TAG_BITS - 1:0] l1d_tag_t;
321:    l1d_tag_t tag;
322:    l1d_set_idx_t set_idx;
323:    logic[CACHE_LINE_OFFSET_WIDTH - 1:0] offset;
324:} l1d_addr_t;
327:typedef logic[$clog2(`L1I_SETS) - 1:0] l1i_set_idx_t;
